-- W1.6 questions batch 6647/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6e2f88c7-moex-00006', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '在嫌疑人張三行收賄案件的偵查中，警察為掌握其與那些人往來，在取
得法官所核發的令狀後，安排了不同車輛停放在其住家對面，對準門口，
拍攝在張三家出入的人員。審判中，檢察官以警察所拍攝的影片作為證
據，張三主張警察的行為違法。請問，張三的主張是否有理由？請依刑
事訴訟法的相關規定詳答。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60ba05060ecb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00007', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '被告張三於證據調查程序中才發現，法官與被害人訂有婚約，於是聲請
法官迴避。檢察官主張，張三已經就案件有所聲明及陳述，已不得聲請
法官迴避。試問，法官應否迴避？原被告雙方何者主張有理由？請附詳
細理由說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60ba05060ecb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00008', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'essay', '甲於民國（下同）112 年 6 月 1 日與乙成立借名登記契約，約定甲出資
向丙購買 A地，並登記於乙之名下。於同年 7 月1 日，甲出資並以乙之
名義與丙簽訂 A地買賣契約，乙並於該買賣契約之買受人欄位簽名，嗣
後丙亦將 A 地所有權移轉登記予乙。於同年 9 月 1 日，乙未經甲之同
意，私自將 A地出售給丁，並於1 個月後完成所有權移轉登記予丁。丁
於同年 11 月 1 日前往 A 地時，甲拒絕丁進入 A 地範圍，雙方並發生肢
體衝突。甲聲稱其與乙就 A地存在借名登記關係，其乃 A地之真正所有
權人，乙僅為出名人且非真正所有權人。乙將 A地出賣給丁之買賣契約
無效，且乙將 A地所有權移轉登記予丁之行為乃為無權處分，亦屬無效。
試問：甲之主張是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00009', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'essay', '甲於民國（下同）114 年 5 月 5 日指定乙、丙及丁等 3 人為見證人（下
合稱乙等 3 人），同年 8 月 8 日甲乙商量撰擬遺囑文字後，並由乙兼代
筆人製作代筆遺囑（下稱系爭遺囑）。同年 8 月 15 日甲與乙等 3人齊聚
一起，並由乙唸讀系爭遺囑內容，而甲以點頭為表達，該系爭遺囑並由
甲及乙等 3人簽名蓋章。試問：系爭遺囑是否有效？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00010', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '依民法規定，有關法律文書中文字與數字之使用，下列敘述何者正確？', '["若應簽名者不識字，可由他人代為簽名。只要當場有二人簽名證明，亦與簽名生同等之效力", "僅按捺指印不可以代替簽名", "同時以文字與號碼表示一定之數量，但兩者不符合時，視為以文字為準", "有使用文字必要之要式行為，不得經由他人代筆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00011', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲將自有A地出租於乙，租期1年，月租金新臺幣（下同）5萬元，乙應每月15日匯入甲在B 銀行帳戶。今年2月底，甲將A地售讓於丙，並於3月1日完成移轉所有權登記。丙並將受讓 A地所有權之情事通知乙，惟至今，乙仍每月將A地租金匯入甲在B銀行帳戶。下列敘述何者 正確？', '["甲仍得基於A地租賃契約，繼續向乙請求支付並取得租金", "該租賃契約因A地移轉而失效", "丙得向乙請求給付相當於租金之不當得利", "丙得向乙請求支付3月1日起，每月5萬元租金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00012', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於消滅時效中斷之敘述，何者正確？', '["消滅時效中斷，乃是於時效將完成時，為避免債務人不清償，而允許時效期間接續延長", "時效，因承認而中斷者，若於承認後6個月內不起訴，視為不中斷", "時效，因起訴而中斷者，若撤回其訴，或因不合法而受駁回之裁判，其裁判確定，視為不中斷", "因起訴而中斷之時效，自受確定判決，或因其他方法訴訟終結時，重行起算之時效期間，均為 5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00013', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '試驗買賣契約之性質為何？', '["附停止條件之契約", "附解除條件之契約", "附始期之契約", "附終期之契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00014', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於期日及期間之敘述，何者錯誤？', '["休息日在期間中而非期間之末日者，不得予以扣除", "民法第120條關於始日不算入之規定，於年齡之計算，即不得適用", "於計算年齡之末日，為星期日、紀念日或其他休息日時，得適用民法第122條有關期日補充與 期間延長之規定", "死亡之月、日無從確定時，得類推適用民法第124條有關年齡計算之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00015', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '丙受僱於甲遊覽公司，擔任旅行團之司機。某日，於載送觀光團前往著名景點旅途中，因分心且 車速過快，致車輛失控而翻落山谷，導致車上之乘客乙受傷，並支出醫療費用新臺幣10萬元， 下列敘述何者錯誤？', '["丙為甲公司之司機，為甲公司之機關，乙得依民法第28條有關法人侵權行為之規定，向甲公 司請求損害賠償", "丙受僱於甲公司，其於執行職務之際，因過失致乙之身體權受侵害，丙之行為構成民法第184 條第1項前段之侵權行為，丙應就其行為負損害賠償責任", "若甲公司能舉證其選任丙及監督丙職務之執行已盡相當注意，其得主張不負賠償責任", "甲公司為丙之僱用人，應依民法第188條第1項有關受僱人與僱用人侵權行為之規定，與丙就 乙之損害，負連帶賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
